package org.apache.commons.csv;
import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

class CSVFormatTest {

    @Test
    void testIsCommentMarkerSet_whenCommentMarkerIsNull() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT;
        // Using reflection to set private field commentMarker to null
        java.lang.reflect.Field commentMarkerField = CSVFormat.class.getDeclaredField("commentMarker");
        commentMarkerField.setAccessible(true);
        commentMarkerField.set(format, null);

        assertFalse(format.isCommentMarkerSet());
    }

    @Test
    void testIsCommentMarkerSet_whenCommentMarkerIsSet() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT;
        // Using reflection to set private field commentMarker to a non-null value
        java.lang.reflect.Field commentMarkerField = CSVFormat.class.getDeclaredField("commentMarker");
        commentMarkerField.setAccessible(true);
        commentMarkerField.set(format, '#');

        assertTrue(format.isCommentMarkerSet());
    }
}
